class DiscountCalculator:
    def calculate_total(self, items, discount_percent):
        subtotal = 0
        for price in items:
            subtotal += price
        discount_value = subtotal * (discount_percent / 100)
        return round(subtotal - discount_value, 2)

tests:
def test_no_discount():
    calc = DiscountCalculator()
    assert calc.calculate_total([10, 20, 30], 0) == 60.0

def test_regular_discount():
    calc = DiscountCalculator()
    assert calc.calculate_total([50, 50], 10) == 90.0

def test_rounding():
    calc = DiscountCalculator()
    assert calc.calculate_total([19.99, 5.01], 10) == 22.5

def test_basic_lowercase():
    assert normalize_email("TEST@EXAMPLE.COM") == "test@example.com"

def test_strip_spaces():
    assert normalize_email("  user@example.com  ") == "user@example.com"

def test_plus_alias():
    assert normalize_email("john+promo@example.com") == "john@example.com"

