function groupByStatus(tasks) {
  const result = {};
  for (const task of tasks) {
    if (!result[task.status]) {
      result[task.status] = [];
    }
    result[task.status].push(task.id);
  }
  return result;
}

module.exports = { groupByStatus };

tests:
const { groupByStatus } = require("./source");

test("groups ids by status", () => {
  expect(groupByStatus([
    { id: 1, status: "open" },
    { id: 2, status: "done" },
    { id: 3, status: "open" }
  ])).toEqual({ open: [1, 3], done: [2] });
});

test("returns empty object on empty input", () => {
  expect(groupByStatus([])).toEqual({});
});

source_code:
export class RetryPolicy {
  execute<T>(fn: () => T, retries: number): T {
    let attempts = 0;
    while (true) {
      try {
        return fn();
      } catch (err) {
        attempts++;
        if (attempts > retries) {
          throw err;
        }
      }
    }
  }
}

tests:
import { RetryPolicy } from "./source";

test("returns successful result", () => {
  const policy = new RetryPolicy();
  expect(policy.execute(() => 42, 2)).toBe(42);
});

test("retries before succeeding", () => {
  const policy = new RetryPolicy();
  let calls = 0;
  const result = policy.execute(() => {
    calls++;
    if (calls < 3) throw new Error("fail");
    return "ok";
  }, 3);
  expect(result).toBe("ok");
  expect(calls).toBe(3);
});

test("throws after max retries", () => {
  const policy = new RetryPolicy();
  expect(() => policy.execute(() => { throw new Error("boom"); }, 1)).toThrow("boom");
});

source_code:
public class ShippingCalculator {
    public int fee(boolean express, int itemCount) {
        int base = 5;
        if (express) {
            base = 15;
        }
        if (itemCount > 3) {
            base += 2;
        }
        return base;
    }
}

tests:
import static org.junit.jupiter.api.Assertions.assertEquals;
import org.junit.jupiter.api.Test;

public class ShippingCalculatorTest {
    @Test
    void standardSmallOrder() {
        assertEquals(5, new ShippingCalculator().fee(false, 1));
    }

    @Test
    void expressSmallOrder() {
        assertEquals(15, new ShippingCalculator().fee(true, 2));
    }

    @Test
    void expressLargeOrder() {
        assertEquals(17, new ShippingCalculator().fee(true, 5));
    }
}

