package source

func CountActive(flags []bool) int {
    count := 0
    for _, flag := range flags {
        if flag {
            count++
        }
    }
    return count
}

tests:
package source

import "testing"

func TestCountActive(t *testing.T) {
    if CountActive([]bool{true, false, true, true}) != 3 {
        t.Fatal("expected 3")
    }
}

func TestCountActiveEmpty(t *testing.T) {
    if CountActive([]bool{}) != 0 {
        t.Fatal("expected 0")
    }
}

source_code:
public class PasswordPolicy
{
    public bool IsValid(string password)
    {
        if (password.Length < 8) return false;
        bool hasDigit = false;
        foreach (char c in password)
        {
            if (char.IsDigit(c))
            {
                hasDigit = true;
            }
        }
        return hasDigit;
    }
}

tests:
using Xunit;

public class PasswordPolicyTests
{
    [Fact]
    public void RejectsShortPassword()
    {
        Assert.False(new PasswordPolicy().IsValid("a1b2"));
    }

    [Fact]
    public void RejectsNoDigit()
    {
        Assert.False(new PasswordPolicy().IsValid("abcdefgh"));
    }

    [Fact]
    public void AcceptsValidPassword()
    {
        Assert.True(new PasswordPolicy().IsValid("abcd1234"));
    }
}

source_code:
pub fn first_non_empty(values: Vec<&str>) -> Option<String> {
    for value in values {
        if !value.is_empty() {
            return Some(value.to_string());
        }
    }
    None
}

tests:
use source::first_non_empty;

#[test]
fn finds_first_non_empty() {
    assert_eq!(first_non_empty(vec!["", "a", "b"]), Some("a".to_string()));
}

#[test]
fn returns_none_when_all_empty() {
    assert_eq!(first_non_empty(vec!["", ""]), None);
}

