class LoyaltyPoints {
    fun award(amount: Int): Int {
        var points = amount / 10
        if (amount > 100) {
            points += 5
        }
        return points
    }
}

tests:
import kotlin.test.Test
import kotlin.test.assertEquals

class LoyaltyPointsTest {
    @Test
    fun basePoints() {
        assertEquals(5, LoyaltyPoints().award(50))
    }

    @Test
    fun bonusPoints() {
        assertEquals(17, LoyaltyPoints().award(120))
    }
}
